                    child: _ShareButton(
                      icon: Icons.share_rounded,
                      label: l10n.actionShare,
                      isPrimary: true,
                      onPressed: () {
                        Navigator.of(context).pop();
                        Share.share(
                          l10n.shareMessage(fractalName, linkText),
                          subject: l10n.shareSubject(fractalName),
